      '자체 제작',
      '5000 3200',
      '1800',
      '정보올림피아드 입문',
      1,
      '{"사칙연산","구현"}'
    ) returning id into new_id;
    insert into public.test_cases (problem_id, stdin, stdout, is_hidden) values
    (new_id, '5000 3200', '1800', false),
    (new_id, '10000 10000', '0', false),
    (new_id, '7000 2500', '4500', true),
    (new_id, '1000000 1', '999999', true);
  end if;
end $$;

